var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"기절했었나...... 분명 폭발음이 들렸는데......","JPN":"気絶してたのか……たしか、爆発音がして……","ENG":"Did I pass out? I thought heard an explosion.","TWN":"暈過去了嗎……明明清楚聽到了爆炸聲……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"반응로는...... 무사해 보이는군요.","JPN":"反応炉は……無事そうですね。","ENG":"The reactor... It looks unscathed.","TWN":"反應爐……看起來沒事啊。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다들 괜찮습니까?","JPN":"皆さん、大丈夫ですか？","ENG":"Is everyone okay?","TWN":"大家都沒事吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_QM","text":{"KOREA":"네. 멀미가 좀 나긴 해도 팔다리는 멀쩡하게 붙어 있네요.","JPN":"はい、少しムカムカしますが、なんとか無事みたいです。","ENG":"Yes. I'm nauseated, but at least I still have all my limbs intact.","TWN":"是。雖然還有點暈，但至少沒有斷手斷腳。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_QM","text":{"KOREA":"어? 아닌가? 새끼발가락에서 감각이 없어진 것 같기도 하고?","JPN":"あれ？　そんなことないかな？　足の小指に感覚がないような……？","ENG":"Oh, wait. My pinky toe feels numb.","TWN":"嗯？沒有嗎？小拇指似乎也沒知覺了？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"......시영 씨, 의뢰인을 깔고 앉아도 된다는 조항은 계약서에 없었어요.","JPN":"……シノンさん、依頼人を座布団代わりにしても良いという内容は契約書にありません。","ENG":"Shiyoung, no clause in your contract says that you can sit on top of your client.","TWN":"……周時雨小姐，契約上沒有允許妳坐在委託人身上的條例。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"엄살 부릴 시간에 그 무거운 엉덩이나 치우도록 하세요.","JPN":"適当な事を言ってないで、その重たいお尻をどかしてください。","ENG":"Please stop complaining and remove your buttocks this instance. They're heavy.","TWN":"可以麻煩妳從我身上下來嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"엇차, 실례.","JPN":"おっと、失礼。","ENG":"Oopsie, sorry.","TWN":"哎呀，失禮了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"누굽니까, 당신들은?!","JPN":"あなた方はどこから……！？","ENG":"Who are you?!","TWN":"你們是誰？！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이곳 1급 군사기밀 시설로, 무단 침입자는 즉시 체포 대상입니다.","JPN":"ここは最上級の軍事機密施設で、無断で入った者は即時逮捕となります。","ENG":"This place is a classified military facility. Unauthorized intruders are to be arrested immediately.","TWN":"這裡是一級軍事機密設施，非法入侵者將立即被逮捕。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"즉시 무기를 내려 놓고 지시에 따르십시오.","JPN":"直ちに武器をおろして、指示に従ってください。","ENG":"Put down your weapons, and follow my instructions.","TWN":"請立刻放下武器並聽從指示。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어─라?","JPN":"あれれ？","ENG":"Err?","TWN":"哦—呀？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양, 혹시나 해서 물어보는 건데 어릴 때 헤어진 쌍둥이 오빠가 계시나요?","JPN":"カリンさん、もしかして、子どもの頃生き別れになった双子のお兄さんがいるんですか？　","ENG":"Karin, just out of curiosity, do you have a twin brother whom you don't know about?","TWN":"卡琳小姐，以防萬一問一下，妳是不是有個幼時失散的雙胞胎哥哥啊？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전 외동딸이에요. 의심되면 출생 기록이라도 열람해 보시던지요.","JPN":"私は一人っ子ですよ。信じられないなら出生記録でも確認してみては？","ENG":"I'm an only child. If you don't believe me, you can check my birth certificate.","TWN":"我是獨生女。不信的話，妳去查查出生記錄啊。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그리고 우리 목적지에는 생명체가 있을 수 없어요.","JPN":"それに、私たちの目的地に生命体がいるわけないです。","ENG":"Besides, there shouldn't be any living things at our destination.","TWN":"還有，我們的目的地不可能有生命體。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"만에 하나 제가 모르는 친족이 있더라도 여기서 만날 확률은 소수점 세 자리 이하입니다.","JPN":"万が一私の知らない親族がいるとしても、ここでバッタリ会うなんて小数点3ケタ以下の確率です。","ENG":"Even if there's a family member that I don't know about, my chance of meeting him here is lower than 0.001.","TWN":"即使有一個我不認識的親戚，我們在這裡相遇的可能性也不到0.001%。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 그럼 저기서 우릴 노려 보고 있는 소년은 누굴까요?","JPN":"ハハ、じゃあ、向こうで私たちのことを睨みつけている少年は誰でしょうね？","ENG":"Hah hah. Then, who's that boy glaring at us from over there?","TWN":"哈哈，那麼那裡盯著我們的少年會是誰呢？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"마지막으로 경고하겠습니다. 무기를 내려 놓고 지시에 따르십시오.","JPN":"最終警告です。武器をおろして、指示に従ってください。","ENG":"This is your last warning. Put down your weapons, and follow my instructions.","TWN":"最後警告。請立即放下武器並聽從指示。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사람이...... 있잖아......?","JPN":"人が……いる……？","ENG":"There really is someone...","TWN":"那邊確實……有人啊……？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"정말 똑같이 생겼죠? 우연이라기엔 성격이나 말투까지 너무 비슷한 것 같은데?","JPN":"本当に瓜二つですよね？　偶然にしては性格や口調まで似すぎてるような……？","ENG":"He really looks like you, doesn't he? He even acts and speaks like you. This can't be a coincidence.","TWN":"長得真的一模一樣耶。要說偶然的話，會連性格和語氣都這麼像嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아니면 삭막한 인생을 살던 카린 양에게 찾아온 운명적인 만남이라거나......?","JPN":"それとも、砂漠のような人生を歩んできたカリンさんに、ついに運命の出会いが訪れたとか……？","ENG":"I wonder if he's your soulmate who showed up to put an end to your bleak days...","TWN":"又或者，對生活索然無味的卡琳小姐來說，這算是個命運的邂逅……？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"쓸데없는 소리는 금지하겠습니다.","JPN":"無駄口は禁止にします。","ENG":"I forbid you from speaking nonsense.","TWN":"禁止說廢話。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"유감이지만 이쪽은 시급한 임무를 수행하고 있는 중입니다.","JPN":"残念ですが、こっちは緊急任務に当たっているので。","ENG":"I'm sorry, but we're on an urgent mission.","TWN":"很遺憾，我們這邊正在執行緊急任務。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신이 누구든 취조실에서 느긋하게 신원 조사나 받고 있을 수는 없어요.","JPN":"あなたが誰だか知りませんが、取調室でのんびり身元調査なんて受けている場合じゃありません。","ENG":"Whoever you are, we can't let you keep us here to satisfy your curiosity about us.","TWN":"不管你是誰，我們也沒辦法陪你在偵訊室裡悠閒地做身份調查了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"신변의 안전보다 임무를 우선하는 태도는 높이 사 드리겠습니다.","JPN":"身の安全より任務を優先する態度は高く買ってあげましょう。","ENG":"I commend you for putting your duty before your safety.","TWN":"妳將任務優先於自身安全的態度，我給予很高的評價。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 지시에 따르지 않는다면, 무력으로 제압하도록 하겠습니다.","JPN":"でも、指示に従わないなら武力で押さえつけるしかありません。","ENG":"But if you refuse to follow my instructions, then I'll have to use force.","TWN":"但如果妳不聽從指示，我們將使用武力進行壓制。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"좋아요. 그렇다면 이쪽도 무력으로 저항해 드리죠.","JPN":"いいでしょう。だったら、私も武力で対抗するしかないですね。","ENG":"Well, if you do, then we'll respond in kind.","TWN":"很好。那麼我這邊也用武力來抵抗吧。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"으음, 남매 싸움 같은데 전 빠져도 되죠?","JPN":"うーん、兄妹ケンカっぽいし、私は外しても大丈夫ですよね？","ENG":"Mm, mind if I sit out this sibling squabble?","TWN":"呃，兄妹吵架的話，那我就閃一邊去囉？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"말씀 조심하십시오. 저는 저런 까탈스러운 여동생 따위 둔 적이 없습니다.","JPN":"発言に気を付けてください。僕にはあんな気難しい妹なんていませんから。","ENG":"Please watch your mouth. I don't have a fastidious sister like her.","TWN":"注意妳的用詞。我從來沒有這麼麻煩的妹妹。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"입조심하세요. 저런 목석 같은 남동생은 한 트럭씩 보급해 줘도 사양하겠습니다.","JPN":"発言を謹んでください。あんな頭でっかちな弟なんて、こっちからお断りです。","ENG":"Please be careful what you say. I don't want an insensitive brother like him.","TWN":"管好妳的嘴巴。就算給我一卡車的好處，我也不會認這種木頭人當哥哥。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......누구더러 목석이라는 겁니까? 정정을 요구합니다.","JPN":"……誰が頭でっかちですか？　訂正を求めます。","ENG":"Who are you calling insensitive? I demand a correction.","TWN":"……妳說誰是木頭人？我要求妳更正妳的言辭。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......까탈스러운 게 아니라 꼼꼼한 거겠죠? 단어 선택이 저급하네요.","JPN":"……気難しいだなんて、几帳面の間違いじゃありませんか？　言葉の選択肢が乏しいですね。","ENG":"You mean meticulous, not fastidious, right? Your vocabulary could use some improvement.","TWN":"……不是麻煩，而是認真吧？你選擇用詞的品味真是糟糕呢。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"주관적인 기준으로 타인을 평가하다니, 조심성 없고 감정적인 인물상이군요.","JPN":"自己基準で他人を評価するなんて、慎重さに欠けていて感情的なお人柄なんですね。","ENG":"Judging others subjectively like that, you're clearly a careless and emotional character.","TWN":"居然以主觀標準評價他人，看來妳是個不謹慎而且情緒化的人。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"피상적인 요소만으로 상황을 파악하다니, 성급한 데다가 사려 깊지 못함을 드러내는군요.","JPN":"表面的な要素だけで状況を把握するとは、性急で思慮が足りないですね。","ENG":"Assessing situations based on superficial elements like this, you're rash and thoughtless.","TWN":"居然單憑表面因素掌握情況，這表示你性急而且欠缺深思熟慮。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중간 평점은 C- 드리겠습니다.","JPN":"中間評価はC-といたしましょう。","ENG":"My interim evaluation of you is C-.","TWN":"我給妳中間評價C-。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"100점 만점에 30점이에요. 분발하셔야겠네요.","JPN":"100点満点中、30点です。もう少し頑張りましょう。","ENG":"I give you 30 out of 100. You'd better try harder.","TWN":"100分是滿分的話我給你30分。看來你還需要再努力。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하!","JPN":"チッ！","ENG":"Ha!","TWN":"哼！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"흥!","JPN":"フン！","ENG":"Hmpf!","TWN":"哼！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"후훗. 남매 싸움 맞는 것 같은데.","JPN":"ふふ、限りなく兄妹ケンカっぽいけど。","ENG":"Heh heh. A sibling squabble, it is.","TWN":"呵呵。看來真的是兄妹吵架。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_BOTH","text":{"KOREA":"시끄럽습니다!","JPN":"うるさいです！","ENG":"Shut up!","TWN":"吵死了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......제 페이스를 흐트러뜨리다니, 실비아 양 이상으로 골치 아픈 작자들이군요.","JPN":"……僕のペースを乱すなんて、シルビアさん以上に困った連中ですね。","ENG":"I bet they're as troublesome as Sylvia, being able to throw me off balance like this.","TWN":"……竟然能夠打亂我的步調，這群傢伙比希爾維亞還要讓人頭痛。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"아뇨. 꽤 죽이 잘 맞으시던데요. 소령님.","JPN":"いや、なかなか息ぴったりでしたよ、少佐。","ENG":"No. I say you'd get along pretty well with them, Major.","TWN":"沒有啊，您與他們非常合得來啊，少校。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"잡담은 금물입니다! 전 대원 전투 태세로!","JPN":"私語は禁物です！　全隊員、戦闘態勢へ！","ENG":"You shouldn't talk unnecessarily! Everyone, get ready to fight!","TWN":"禁止聊天！全體隊員進入戰鬥狀態！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"경고는 충분히 했습니다! 침입자를 제압하십시오!","JPN":"もう十分に警告しました！　侵入者を制圧してください！","ENG":"I've warned you! Subdue the intruders!","TWN":"我們已經做了十足的警告！開始制服入侵者！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이런, 벌써 포위당했는데요? 카린 양, 고생하시겠어요.","JPN":"あらあら、もう取り囲まれちゃいましたね？　カリンさん、ご苦労さまです。","ENG":"Uh-oh, we're already surrounded. Karin, I'm sorry for you.","TWN":"喔，妳已經被包圍了耶，卡琳小姐，看來妳有麻煩了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"파견원이면 파견원답게 구경할 생각 말고 어서 일이나 거드세요!","JPN":"見てないで、派遣隊員らしく手伝ってくださいよ！","ENG":"You've been dispatched to help. Stop watching and start helping!","TWN":"如果妳是個派遣員，就別只顧著看戲，快過來幫忙！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"으음......","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하긴 뭐, 24시간밖에 안 남은 목숨인데 여부가 있겠어요.","JPN":"まあ、どうせ残り24時間の命ですし、やるっきゃないですね。","ENG":"Well, sure, why not? I've only got 24 hours to live, anyway.","TWN":"這麼說也是，我的生命只剩24小時，也不能怎麼樣了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼 실례 좀 할게요, 여러분?","JPN":"では、ちょっと失礼しますね、皆さん？","ENG":"Then, excuse me, everyone.","TWN":"那就失禮囉，各位。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};